#include <stdio.h>

void Swap(int a, int b);

int main()

{

    int a, b;

    printf("Input a, b:");

    scanf("%d %d", &a, &b);

    Swap(a, b); 

    printf("In main():a = %d, b = %d\n", a, b);

    return 0;

}

void Swap(int a, int b)

{

    int temp;

    temp = a;

    a = b;

    b = temp;

    printf("In Swap():a = %d, b = %d\n", a, b);

}

可以使用指针参数的方式来传递变量的地址，通过指针访问变量的值，实现变量交换的目的。新的`Swap()`函数代码如下所示：

```
void Swap(int* a, int* b)
{
    int temp;
    temp = *a;
    *a = *b;
    *b = temp;
}
```

在主函数中调用`Swap()`函数时，传递变量a和b的地址即可。代码如下所示：

```
int a, b;
printf("Input a, b:");
scanf("%d %d", &a, &b);
Swap(&a, &b);
printf("In main():a = %d, b = %d\n", a, b);
```

运行程序，输入两个数a和b，程序会交换其值并输出。

